#include<bits/stdc++.h>
using namespace std;
int n,m,q;
vector<int> mp[200010];
int dp[200010][5][3];
int dfs(int x,int k,int id)
{
    if(dp[x][k][id])
    {
        return dp[x][k][id];
    }
    if(k==0)
    {
        return x;
    }
    if(id==1)
    {
        int max1=0;
        for(int i:mp[x])
        {
            max1=max({max1,i,dfs(i,k-1,2)});
        }
        return dp[x][k][id]=max1;
    }
    else
    {
        int min1=1e9;
        for(int i:mp[x])
        {
            min1=min({min1,max(i,dfs(i,k-1,1))});
        }
        return dp[x][k][id]=max(min1,x);
    }
}
int main()
{
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    while(q--)
    {
        int x,k;
        scanf("%d%d",&x,&k);
        printf("%d\n",dfs(x,min(k,3),1));
    }
    return 0;
}
